import { html, customElement } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FormsPrevalueSourceDetailRepository } from '../../../repository/index.js';
import { FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE } from '../../../entities.js';
import type { FieldPreValueSource } from '../../../../../generated/index.js';
import type { FormsPrevalueSourceDeleteConfirmModalData } from './index.js';

@customElement('forms-prevaluesource-delete-confirm-modal')
export class FormsPrevalueSourceDeleteConfirmModalElement extends UmbModalBaseElement<FormsPrevalueSourceDeleteConfirmModalData> {

	#formToDelete?: FieldPreValueSource | null;

	#prevalueSourceDetailRepository = new FormsPrevalueSourceDetailRepository(this);

	async connectedCallback() {
		super.connectedCallback();

		if (!this.data?.unique) return;

		const formToDeleteResponse = await this.#prevalueSourceDetailRepository.requestByUnique(this.data.unique);
		this.#formToDelete = formToDeleteResponse.data;

		this.requestUpdate();
	}

	async #deletePrevalueSource(event: PointerEvent) {
		event.stopPropagation();

		if (this.data?.unique) {
			await this.#prevalueSourceDetailRepository.delete(this.data.unique);

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			const eventArgs = {
				entityType: FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE,
				unique: null,
			};
			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent(eventArgs);
			eventContext.dispatchEvent(reloadEvent);
		}
		this._submitModal();
	}

	render() {
		return html`
			<umb-body-layout headline=${this.localize.term("formPrevalueSources_deletePrevalueSource")}>
				<uui-box>
					<p>${this.localize.term("formPrevalueSources_deleteConfirm", this.#formToDelete?.name)}</p>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term("general_cancel")} @click="${this._rejectModal}">${this.localize.term("general_cancel")}</uui-button>
				<uui-button slot="actions" type="button" label=${this.localize.term("general_delete")} look="primary" color="danger" @click=${this.#deletePrevalueSource}></uui-button>
			</umb-body-layout>
		`;
	}
}

export default FormsPrevalueSourceDeleteConfirmModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-prevaluesource-delete-confirm-modal': FormsPrevalueSourceDeleteConfirmModalElement;
	}
}
